import {useMemo} from 'react';

export function InvoiceTotals({items, taxRate}: {items: readonly LineItem[]; taxRate: number}) {
  const subtotal = useMemo(() => items.reduce((sum, item) => sum + item.priceCents * item.quantity, 0), [items]);
  const total = Math.round(subtotal * (1 + taxRate));
  return <TotalView subtotal={subtotal} total={total} />;
}

